import{_ as l,o as r,c as a,ag as o}from"./chunks/framework.DEs8X8sU.js";const u=JSON.parse('{"title":"Part 3 — メニュー管理","description":"","frontmatter":{"title":"Part 3 — メニュー管理","audience":"オーナー / 店長","prerequisite":"Part 0 + Part 1","last_updated":"2026-04-18T00:00:00.000Z"},"headers":[],"relativePath":"operations/part3-menu.md","filePath":"operations/part3-menu.md"}'),i={name:"operations/part3-menu.md"};function e(n,t,s,d,h,g){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="part-3-—-メニュー管理" tabindex="-1">Part 3 — メニュー管理 <a class="header-anchor" href="#part-3-—-メニュー管理" aria-label="Permalink to &quot;Part 3 — メニュー管理&quot;">​</a></h1><p>このページでは、お店のメニューを POSLA に登録・編集する方法を、<strong>ボタンの押し方 1 つずつ</strong> 説明します。</p><div class="tip custom-block"><p class="custom-block-title">メニュー管理の考え方（重要）</p><p>POSLA のメニューは、複数店舗でも運用しやすいように次の考え方で管理します。</p><ol><li><strong>全店共通メニュー</strong> — ブランド全体で共通して販売する商品</li><li><strong>店舗ごとの調整</strong> — 店舗ごとの価格変更・非表示・売切設定</li><li><strong>店舗限定メニュー</strong> — その店舗だけで販売する商品</li></ol><p>この仕組みにより、同じブランド内で <strong>「全店共通メニュー + 店舗限定メニュー」</strong> を両立できます。</p></div><div class="warning custom-block"><p class="custom-block-title">本部一括配信アドオン契約時の特殊運用</p><p>本部一括配信アドオンを契約している場合:</p><ul><li>全店共通メニューの追加・編集は <strong>オーナー管理画面の「本部メニュー」タブ</strong> から行います</li><li>各店舗の管理画面では、共通メニューの商品名・基本価格・カロリー・アレルゲン・画像などは編集できません</li><li>各店舗で変更できるのは、店舗別価格・非表示・売切などの運用項目です</li></ul><p>アドオン未契約の場合は、店舗管理画面から通常どおりメニューを追加・編集できます。</p></div><hr><h2 id="_3-1-新しいメニューを追加する" tabindex="-1">3-1. 新しいメニューを追加する <a class="header-anchor" href="#_3-1-新しいメニューを追加する" aria-label="Permalink to &quot;3-1. 新しいメニューを追加する&quot;">​</a></h2><h3 id="_3-1-1-通常-アドオン未契約-の場合" tabindex="-1">3-1-1. 通常（アドオン未契約）の場合 <a class="header-anchor" href="#_3-1-1-通常-アドオン未契約-の場合" aria-label="Permalink to &quot;3-1-1. 通常（アドオン未契約）の場合&quot;">​</a></h3><ol><li>管理画面にログイン</li><li>上部タブ <strong>【メニュー管理】</strong> → サブタブ <strong>【店舗メニュー】</strong></li><li>画面右上の <strong>【+ メニュー追加】</strong> ボタン</li><li>モーダルが開く</li><li>以下を入力:</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td><strong>品名</strong></td><td>✅</td><td>日本語名（例: <code>鶏の唐揚げ</code>）</td></tr><tr><td><strong>品名（英語）</strong></td><td>—</td><td>任意（例: <code>Fried Chicken</code>）</td></tr><tr><td><strong>カテゴリ</strong></td><td>✅</td><td>ドロップダウンから選択</td></tr><tr><td><strong>基本価格</strong></td><td>✅</td><td>円（例: <code>900</code>）</td></tr><tr><td><strong>カロリー</strong></td><td>—</td><td>kcal 単位（例: <code>380</code>）</td></tr><tr><td><strong>アレルゲン</strong></td><td>—</td><td>卵 / 乳 / 小麦 / 落花生 / えび / かに / そば のチェックボックス</td></tr><tr><td><strong>画像URL</strong></td><td>—</td><td>HTTPS の URL（<code>https://...</code>）</td></tr></tbody></table><ol start="6"><li><strong>【保存】</strong></li><li>セルフメニュー・ハンディに即反映（お客様側は次回リロード、または 3 分キャッシュ）</li></ol><h3 id="_3-1-2-アドオン契約時の場合" tabindex="-1">3-1-2. アドオン契約時の場合 <a class="header-anchor" href="#_3-1-2-アドオン契約時の場合" aria-label="Permalink to &quot;3-1-2. アドオン契約時の場合&quot;">​</a></h3><p>本部一括配信アドオンを契約中のテナントでは、店舗側から本部マスタは追加できません。</p><ol><li>オーナー管理画面にオーナーアカウントでログイン</li><li><strong>【本部メニュー】</strong> タブ</li><li><strong>【+ 本部メニュー追加】</strong> ボタン</li><li>本部マスタとして追加（全店共通メニューになる）</li></ol><p>店舗側で <strong>「この店舗だけのメニュー」</strong> を追加したい場合は、3-6「限定メニュー」を参照。</p><hr><h2 id="_3-2-メニューの価格を変更する" tabindex="-1">3-2. メニューの価格を変更する <a class="header-anchor" href="#_3-2-メニューの価格を変更する" aria-label="Permalink to &quot;3-2. メニューの価格を変更する&quot;">​</a></h2><h3 id="_3-2-1-全店共通の価格を変える-本部マスタ" tabindex="-1">3-2-1. 全店共通の価格を変える（本部マスタ） <a class="header-anchor" href="#_3-2-1-全店共通の価格を変える-本部マスタ" aria-label="Permalink to &quot;3-2-1. 全店共通の価格を変える（本部マスタ）&quot;">​</a></h3><p>アドオン未契約: 管理画面の「店舗メニュー」→ 編集で直接変更 アドオン契約中: オーナー管理画面「本部メニュー」→ 編集</p><h3 id="_3-2-2-店舗別の価格を上書きする-店舗オーバーライド" tabindex="-1">3-2-2. 店舗別の価格を上書きする（店舗オーバーライド） <a class="header-anchor" href="#_3-2-2-店舗別の価格を上書きする-店舗オーバーライド" aria-label="Permalink to &quot;3-2-2. 店舗別の価格を上書きする（店舗オーバーライド）&quot;">​</a></h3><p>同じ商品を店舗ごとに別価格で売りたい場合。</p><ol><li>管理画面 → 【メニュー管理】 → 【店舗メニュー】</li><li>該当メニューの <strong>【編集】</strong> ボタン</li><li><strong>「店舗価格（上書き）」</strong> 欄に新しい価格を入力 <ul><li>例: 本部価格 ¥900 / 渋谷店（価格上書き）¥1,000 / 新宿店（価格上書きなし）→ ¥900</li></ul></li><li><strong>【保存】</strong></li><li>セルフメニュー・ハンディに店舗別価格が反映される</li></ol><p><strong>クリアするには</strong>: 同じ欄を空白にして保存します。空白に戻すと、全店共通の基本価格が適用されます。</p><h3 id="_3-2-3-単純な価格変更の手順-本部価格変更" tabindex="-1">3-2-3. 単純な価格変更の手順（本部価格変更） <a class="header-anchor" href="#_3-2-3-単純な価格変更の手順-本部価格変更" aria-label="Permalink to &quot;3-2-3. 単純な価格変更の手順（本部価格変更）&quot;">​</a></h3><ol><li>【店舗メニュー】で該当メニューの <strong>【編集】</strong></li><li><strong>基本価格</strong> 欄を変更</li><li><strong>【保存】</strong></li></ol><hr><h2 id="_3-3-メニューの写真-画像-を登録する" tabindex="-1">3-3. メニューの写真（画像）を登録する <a class="header-anchor" href="#_3-3-メニューの写真-画像-を登録する" aria-label="Permalink to &quot;3-3. メニューの写真（画像）を登録する&quot;">​</a></h2><h3 id="_3-3-1-画像の準備" tabindex="-1">3-3-1. 画像の準備 <a class="header-anchor" href="#_3-3-1-画像の準備" aria-label="Permalink to &quot;3-3-1. 画像の準備&quot;">​</a></h3><ul><li>推奨サイズ: <strong>800×600px</strong> または <strong>1000×750px</strong>（4:3 比率）</li><li>フォーマット: JPG または PNG</li><li>ファイルサイズ: 200KB 以下推奨（軽いほうが表示が早い）</li><li>明るく・清潔感のある写真</li></ul><h3 id="_3-3-2-画像を公開-url-にアップロード" tabindex="-1">3-3-2. 画像を公開 URL にアップロード <a class="header-anchor" href="#_3-3-2-画像を公開-url-にアップロード" aria-label="Permalink to &quot;3-3-2. 画像を公開 URL にアップロード&quot;">​</a></h3><p>POSLA 側に画像アップロード機能はないため、<strong>別サービスで公開アップロード</strong>してから URL を取得してください。</p><p>推奨サービス:</p><ul><li><strong>Imgur</strong>（無料、<code>imgur.com</code>）— 一番簡単</li><li>自社ホームページや画像管理サービス</li><li><strong>Cloudinary</strong>（無料枠あり、画像最適化も）</li><li><strong>店舗のホームページ</strong>（WordPress 等）</li></ul><p>手順（Imgur の場合）:</p><ol><li><code>imgur.com</code> にブラウザでアクセス</li><li><strong>「New post」</strong> ボタン → 画像をドラッグ&amp;ドロップ</li><li>アップロード完了後、画像を右クリック → <strong>「画像アドレスをコピー」</strong></li><li>URL は <code>https://i.imgur.com/xxxxx.jpg</code> のような形式</li></ol><h3 id="_3-3-3-posla-に-url-を登録" tabindex="-1">3-3-3. POSLA に URL を登録 <a class="header-anchor" href="#_3-3-3-posla-に-url-を登録" aria-label="Permalink to &quot;3-3-3. POSLA に URL を登録&quot;">​</a></h3><ol><li>該当メニューの <strong>【編集】</strong></li><li><strong>画像URL</strong> 欄にコピーした URL を貼り付け</li><li><strong>【保存】</strong></li><li>プレビュー画像がサムネイル表示される</li></ol><h3 id="_3-3-4-よくあるエラー" tabindex="-1">3-3-4. よくあるエラー <a class="header-anchor" href="#_3-3-4-よくあるエラー" aria-label="Permalink to &quot;3-3-4. よくあるエラー&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>画像が表示されない</td><td>URL が HTTP（http://）になっている</td><td>HTTPS（<code>https://</code>）の URL に変更</td></tr><tr><td>404 エラー</td><td>URL が無効 / 画像が削除された</td><td>Imgur で画像を確認、URL 再取得</td></tr><tr><td>崩れて表示</td><td>極端なアスペクト比</td><td>4:3 または正方形推奨</td></tr><tr><td>画像が重くて遅い</td><td>ファイルサイズが大きすぎ</td><td>200KB 以下に圧縮（<code>tinypng.com</code> 等で）</td></tr></tbody></table><hr><h2 id="_3-4-カテゴリの追加・並べ替え" tabindex="-1">3-4. カテゴリの追加・並べ替え <a class="header-anchor" href="#_3-4-カテゴリの追加・並べ替え" aria-label="Permalink to &quot;3-4. カテゴリの追加・並べ替え&quot;">​</a></h2><h3 id="_3-4-1-カテゴリとは" tabindex="-1">3-4-1. カテゴリとは <a class="header-anchor" href="#_3-4-1-カテゴリとは" aria-label="Permalink to &quot;3-4-1. カテゴリとは&quot;">​</a></h3><p>メニューを分類するグループです。セルフメニュー画面で横タブとして表示されます。</p><p>例:</p><ul><li>前菜 / メイン / ご飯もの / デザート / ドリンク</li><li>鮮魚 / 寿司 / 天ぷら / ご飯もの / デザート</li><li>串 / 刺身 / サラダ / ご飯 / ドリンク</li></ul><h3 id="_3-4-2-カテゴリを追加する" tabindex="-1">3-4-2. カテゴリを追加する <a class="header-anchor" href="#_3-4-2-カテゴリを追加する" aria-label="Permalink to &quot;3-4-2. カテゴリを追加する&quot;">​</a></h3><ol><li>管理画面 → 【メニュー管理】 → サブタブ <strong>【カテゴリ管理】</strong></li><li><strong>【+ カテゴリ追加】</strong> ボタン</li><li>モーダル: <ul><li><strong>カテゴリ名</strong>（例: 「デザート」）</li><li><strong>カテゴリ名（英語）</strong>（例: <code>Dessert</code>）</li><li><strong>並び順</strong>（数値、小さいほど上に表示。例: 5）</li></ul></li><li><strong>【保存】</strong></li></ol><h3 id="_3-4-3-並べ替え" tabindex="-1">3-4-3. 並べ替え <a class="header-anchor" href="#_3-4-3-並べ替え" aria-label="Permalink to &quot;3-4-3. 並べ替え&quot;">​</a></h3><ol><li>該当カテゴリの <strong>【編集】</strong></li><li><strong>並び順</strong> の数値を変更</li><li><strong>【保存】</strong></li></ol><div class="info custom-block"><p class="custom-block-title">ドラッグ&amp;ドロップ並び替えは今後実装予定</p><p>現状は数値入力方式。視覚的な並び替えは将来のアップデートで対応予定。</p></div><h3 id="_3-4-4-カテゴリの削除" tabindex="-1">3-4-4. カテゴリの削除 <a class="header-anchor" href="#_3-4-4-カテゴリの削除" aria-label="Permalink to &quot;3-4-4. カテゴリの削除&quot;">​</a></h3><ol><li>該当カテゴリの <strong>【削除】</strong> ボタン</li><li>確認ダイアログ</li><li><strong>削除前の警告</strong>: そのカテゴリに紐付く品目がある場合、削除できない（品目のカテゴリを先に変更する必要あり）</li></ol><hr><h2 id="_3-5-オプション-トッピング等-の設定" tabindex="-1">3-5. オプション（トッピング等）の設定 <a class="header-anchor" href="#_3-5-オプション-トッピング等-の設定" aria-label="Permalink to &quot;3-5. オプション（トッピング等）の設定&quot;">​</a></h2><h3 id="_3-5-1-オプションとは" tabindex="-1">3-5-1. オプションとは <a class="header-anchor" href="#_3-5-1-オプションとは" aria-label="Permalink to &quot;3-5-1. オプションとは&quot;">​</a></h3><p>メニューに追加で選べる項目。例:</p><ul><li>「唐揚げ」に対して <strong>【サイズ選択】</strong>（小 / 中 / 大、+価格）</li><li>「パスタ」に対して <strong>【ソース選択】</strong>（トマト / クリーム / ペペロンチーノ）</li><li>「ラーメン」に対して <strong>【トッピング】</strong>（煮卵 +100 / チャーシュー +200 / コーン +50）</li></ul><h3 id="_3-5-2-オプショングループを作る" tabindex="-1">3-5-2. オプショングループを作る <a class="header-anchor" href="#_3-5-2-オプショングループを作る" aria-label="Permalink to &quot;3-5-2. オプショングループを作る&quot;">​</a></h3><ol><li>管理画面 → 【メニュー管理】 → サブタブ <strong>【オプション管理】</strong></li><li><strong>【+ オプショングループ追加】</strong> ボタン</li><li>モーダル:</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td><strong>グループ名</strong></td><td>例: 「トッピング」</td></tr><tr><td><strong>グループ名（英語）</strong></td><td>例: <code>Toppings</code></td></tr><tr><td><strong>選択必須</strong></td><td>トグル ON/OFF（必須にするとお客様が必ず選ばなければならない）</td></tr><tr><td><strong>複数選択可</strong></td><td>トグル ON/OFF（ON なら客が複数選べる）</td></tr><tr><td><strong>並び順</strong></td><td>数値</td></tr></tbody></table><ol start="4"><li><strong>【保存】</strong></li><li>グループが一覧に追加される</li></ol><h3 id="_3-5-3-グループに選択肢を追加する" tabindex="-1">3-5-3. グループに選択肢を追加する <a class="header-anchor" href="#_3-5-3-グループに選択肢を追加する" aria-label="Permalink to &quot;3-5-3. グループに選択肢を追加する&quot;">​</a></h3><ol><li>作成したグループの行で <strong>【＋ 選択肢追加】</strong> をタップ</li><li>モーダル: <ul><li><strong>選択肢名</strong>（例: 「チーズ増し」）</li><li><strong>選択肢名（英語）</strong>（例: <code>Extra Cheese</code>）</li><li><strong>追加価格</strong>（例: <code>200</code> で +¥200、<code>0</code> なら価格変動なし）</li></ul></li><li><strong>【保存】</strong></li><li>繰り返して選択肢を増やす（例: チーズ増し、コーン、煮卵）</li></ol><h3 id="_3-5-4-選択肢をメニューに紐付ける" tabindex="-1">3-5-4. 選択肢をメニューに紐付ける <a class="header-anchor" href="#_3-5-4-選択肢をメニューに紐付ける" aria-label="Permalink to &quot;3-5-4. 選択肢をメニューに紐付ける&quot;">​</a></h3><ol><li>【メニュー管理】 → 【店舗メニュー】</li><li>該当メニューの <strong>【編集】</strong></li><li><strong>「オプショングループ」</strong> セクション</li><li>使いたいグループのチェックボックスを ON</li><li><strong>【保存】</strong></li><li>セルフメニューで該当メニューをお客様が選ぶと、オプション選択モーダルが自動で開く</li></ol><hr><h2 id="_3-6-限定メニュー-店舗独自品-の追加" tabindex="-1">3-6. 限定メニュー（店舗独自品）の追加 <a class="header-anchor" href="#_3-6-限定メニュー-店舗独自品-の追加" aria-label="Permalink to &quot;3-6. 限定メニュー（店舗独自品）の追加&quot;">​</a></h2><p>本部マスタにない、その店舗だけのメニュー。</p><h3 id="_3-6-1-手順" tabindex="-1">3-6-1. 手順 <a class="header-anchor" href="#_3-6-1-手順" aria-label="Permalink to &quot;3-6-1. 手順&quot;">​</a></h3><ol><li>管理画面 → 【メニュー管理】 → サブタブ <strong>【限定メニュー】</strong></li><li><strong>【+ 限定メニュー追加】</strong> ボタン</li><li>モーダル: <ul><li>品名</li><li>品名（英語）</li><li>カテゴリ（本部マスタのカテゴリを流用）</li><li>価格</li><li>カロリー・アレルゲン（任意）</li><li>画像URL（任意）</li></ul></li><li><strong>【保存】</strong></li><li>セルフメニューに <strong>「限定」</strong> ピンクバッジ付きで表示される</li></ol><h3 id="_3-6-2-限定メニューの使いどころ" tabindex="-1">3-6-2. 限定メニューの使いどころ <a class="header-anchor" href="#_3-6-2-限定メニューの使いどころ" aria-label="Permalink to &quot;3-6-2. 限定メニューの使いどころ&quot;">​</a></h3><ul><li><strong>季節メニュー</strong>: 冬の鍋メニュー、春のお花見弁当など</li><li><strong>店舗独自開発品</strong>: 渋谷店シェフのオリジナル料理</li><li><strong>試作メニュー</strong>: 特定店舗でテスト販売してから本部マスタに昇格</li></ul><hr><h2 id="_3-7-多言語翻訳-英語・中国語・韓国語等" tabindex="-1">3-7. 多言語翻訳（英語・中国語・韓国語等） <a class="header-anchor" href="#_3-7-多言語翻訳-英語・中国語・韓国語等" aria-label="Permalink to &quot;3-7. 多言語翻訳（英語・中国語・韓国語等）&quot;">​</a></h2><h3 id="_3-7-1-自動一括翻訳" tabindex="-1">3-7-1. 自動一括翻訳 <a class="header-anchor" href="#_3-7-1-自動一括翻訳" aria-label="Permalink to &quot;3-7-1. 自動一括翻訳&quot;">​</a></h3><p>メニュー全体を一度に翻訳。</p><ol><li>管理画面 → 【メニュー管理】 → 【店舗メニュー】</li><li>画面右上の <strong>【🌐 一括翻訳】</strong> ボタン</li><li>モーダルで翻訳先言語をチェック: <ul><li>☑ English</li><li>☑ 中文（簡体字）</li><li>☑ 繁體中文</li><li>☑ 한국어</li></ul></li><li><strong>【翻訳開始】</strong></li><li>AI（Gemini）が数十秒で全品目・カテゴリを一括翻訳</li><li>「翻訳完了」トースト表示</li></ol><h3 id="_3-7-2-強制再翻訳" tabindex="-1">3-7-2. 強制再翻訳 <a class="header-anchor" href="#_3-7-2-強制再翻訳" aria-label="Permalink to &quot;3-7-2. 強制再翻訳&quot;">​</a></h3><p>既に翻訳済みのものを上書きしたい時。</p><ol><li>一括翻訳ダイアログで <strong>「🔄 強制再翻訳」</strong> チェックボックス ON</li><li><strong>【翻訳開始】</strong></li><li>既存の翻訳を上書き</li></ol><h3 id="_3-7-3-個別修正" tabindex="-1">3-7-3. 個別修正 <a class="header-anchor" href="#_3-7-3-個別修正" aria-label="Permalink to &quot;3-7-3. 個別修正&quot;">​</a></h3><p>AI の訳が気に入らない場合。</p><ol><li>該当メニューの <strong>【編集】</strong></li><li><strong>品名（英語）</strong> 欄に手動入力（例: <code>Fried Chicken Curry Rice</code>）</li><li><strong>【保存】</strong></li></ol><h3 id="_3-7-4-お客様側での言語切替" tabindex="-1">3-7-4. お客様側での言語切替 <a class="header-anchor" href="#_3-7-4-お客様側での言語切替" aria-label="Permalink to &quot;3-7-4. お客様側での言語切替&quot;">​</a></h3><ul><li>セルフメニュー画面右上の言語ボタン（🌐）でお客様が切替</li><li>日本語 / English / 中文 / 繁體 / 한국어 の 5 言語</li></ul><hr><h2 id="_3-8-csv-でメニューを一括登録する" tabindex="-1">3-8. CSV でメニューを一括登録する <a class="header-anchor" href="#_3-8-csv-でメニューを一括登録する" aria-label="Permalink to &quot;3-8. CSV でメニューを一括登録する&quot;">​</a></h2><p>大量のメニューを一度に登録する場合は CSV 一括登録が便利。</p><h3 id="_3-8-1-エクスポート-バックアップ・雛形取得" tabindex="-1">3-8-1. エクスポート（バックアップ・雛形取得） <a class="header-anchor" href="#_3-8-1-エクスポート-バックアップ・雛形取得" aria-label="Permalink to &quot;3-8-1. エクスポート（バックアップ・雛形取得）&quot;">​</a></h3><ol><li>【店舗メニュー】 → <strong>【CSV エクスポート】</strong> ボタン</li><li>ダウンロードフォルダに CSV 保存</li><li>Excel / Numbers で開く</li></ol><h3 id="_3-8-2-csv-の編集" tabindex="-1">3-8-2. CSV の編集 <a class="header-anchor" href="#_3-8-2-csv-の編集" aria-label="Permalink to &quot;3-8-2. CSV の編集&quot;">​</a></h3><p>CSV には、画面から入力する内容と同じ項目を入れます。</p><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td>品名（日本語）</td><td>✅</td><td>メニュー名</td></tr><tr><td>価格</td><td>✅</td><td>円単位の販売価格</td></tr><tr><td>カテゴリ</td><td>✅</td><td>既存カテゴリと同じ名前</td></tr><tr><td>英語名</td><td>—</td><td>多言語表示で使う名称</td></tr><tr><td>カロリー</td><td>—</td><td>kcal 単位</td></tr><tr><td>アレルゲン</td><td>—</td><td>卵・乳・小麦など</td></tr><tr><td>画像URL</td><td>—</td><td>画像を表示するためのURL</td></tr></tbody></table><h3 id="_3-8-3-インポート-一括登録" tabindex="-1">3-8-3. インポート（一括登録） <a class="header-anchor" href="#_3-8-3-インポート-一括登録" aria-label="Permalink to &quot;3-8-3. インポート（一括登録）&quot;">​</a></h3><ol><li>【店舗メニュー】 → <strong>【CSV インポート】</strong> ボタン</li><li>CSV ファイルを選択</li><li>プレビュー画面で内容確認</li><li>エラーがあれば修正指示が表示される</li><li><strong>【インポート実行】</strong></li><li>一括登録完了</li></ol><h3 id="_3-8-4-文字化け対処" tabindex="-1">3-8-4. 文字化け対処 <a class="header-anchor" href="#_3-8-4-文字化け対処" aria-label="Permalink to &quot;3-8-4. 文字化け対処&quot;">​</a></h3><p>日本語が文字化けする場合:</p><ul><li><strong>Windows Excel</strong>: 保存時に <strong>「CSV UTF-8（コンマ区切り）」</strong> を選択</li><li><strong>Mac Numbers</strong>: デフォルトで UTF-8 なので OK</li><li><strong>Google Sheets</strong>: ファイル → ダウンロード → カンマ区切りの値（UTF-8）</li></ul><hr><h2 id="_3-9-スマレジからメニューをインポートする" tabindex="-1">3-9. スマレジからメニューをインポートする <a class="header-anchor" href="#_3-9-スマレジからメニューをインポートする" aria-label="Permalink to &quot;3-9. スマレジからメニューをインポートする&quot;">​</a></h2><p>スマレジを使っているお店が POSLA に移行する場合、メニューを自動移行できます。</p><p>詳細は <strong>22 章「スマレジ連携の全設定」</strong> 参照。</p><h3 id="簡易手順" tabindex="-1">簡易手順 <a class="header-anchor" href="#簡易手順" aria-label="Permalink to &quot;簡易手順&quot;">​</a></h3><ol><li>オーナーアカウントでオーナー管理画面 → <strong>【外部POS連携】</strong> タブ</li><li><strong>【OAuth 接続】</strong> → スマレジに既存アカウントでログイン</li><li>許可を与える</li><li><strong>【商品インポート】</strong> ボタン</li><li>非破壊インポート（既存 POSLA メニューは維持、スマレジの商品だけ追加）</li></ol><hr><h2 id="_3-10-本部メニューの管理-チェーン店のみ" tabindex="-1">3-10. 本部メニューの管理（チェーン店のみ） <a class="header-anchor" href="#_3-10-本部メニューの管理-チェーン店のみ" aria-label="Permalink to &quot;3-10. 本部メニューの管理（チェーン店のみ）&quot;">​</a></h2><p>本部一括配信アドオン契約時のみ利用できます。</p><h3 id="_3-10-1-本部メニュータブの場所" tabindex="-1">3-10-1. 本部メニュータブの場所 <a class="header-anchor" href="#_3-10-1-本部メニュータブの場所" aria-label="Permalink to &quot;3-10-1. 本部メニュータブの場所&quot;">​</a></h3><ol><li>オーナーアカウントでオーナー管理画面</li><li>上部タブ <strong>【本部メニュー】</strong></li></ol><h3 id="_3-10-2-本部メニューの追加・編集" tabindex="-1">3-10-2. 本部メニューの追加・編集 <a class="header-anchor" href="#_3-10-2-本部メニューの追加・編集" aria-label="Permalink to &quot;3-10-2. 本部メニューの追加・編集&quot;">​</a></h3><ol><li><strong>【+ 本部メニュー追加】</strong></li><li>モーダルで品名・価格・カテゴリ入力</li><li><strong>【保存】</strong></li><li>全店舗に自動配信される</li></ol><h3 id="_3-10-3-本部-csv-一括管理" tabindex="-1">3-10-3. 本部 CSV 一括管理 <a class="header-anchor" href="#_3-10-3-本部-csv-一括管理" aria-label="Permalink to &quot;3-10-3. 本部 CSV 一括管理&quot;">​</a></h3><ol><li><strong>【CSV エクスポート】</strong></li><li><strong>【CSV インポート】</strong></li></ol><h3 id="_3-10-4-カテゴリフィルタ" tabindex="-1">3-10-4. カテゴリフィルタ <a class="header-anchor" href="#_3-10-4-カテゴリフィルタ" aria-label="Permalink to &quot;3-10-4. カテゴリフィルタ&quot;">​</a></h3><p>本部メニューが多くなったら、画面上部のカテゴリ選択で絞り込みます。</p><h3 id="_3-10-5-店舗側での本部メニュー編集制限" tabindex="-1">3-10-5. 店舗側での本部メニュー編集制限 <a class="header-anchor" href="#_3-10-5-店舗側での本部メニュー編集制限" aria-label="Permalink to &quot;3-10-5. 店舗側での本部メニュー編集制限&quot;">​</a></h3><p>アドオン契約中、各店舗の管理画面では全店共通メニューの基本情報は編集できません。店舗側で変更できるのは次の項目です。</p><ul><li>店舗別価格</li><li>非表示</li><li>売切</li></ul><hr><h2 id="_3-11-今日のおすすめ-日替わり推し商品" tabindex="-1">3-11. 今日のおすすめ（日替わり推し商品） <a class="header-anchor" href="#_3-11-今日のおすすめ-日替わり推し商品" aria-label="Permalink to &quot;3-11. 今日のおすすめ（日替わり推し商品）&quot;">​</a></h2><h3 id="_3-11-1-機能概要" tabindex="-1">3-11-1. 機能概要 <a class="header-anchor" href="#_3-11-1-機能概要" aria-label="Permalink to &quot;3-11-1. 機能概要&quot;">​</a></h3><p>特定のメニューを「今日のおすすめ」として、セルフメニュー画面の上部に目立つように表示する機能。</p><h3 id="_3-11-2-設定手順" tabindex="-1">3-11-2. 設定手順 <a class="header-anchor" href="#_3-11-2-設定手順" aria-label="Permalink to &quot;3-11-2. 設定手順&quot;">​</a></h3><ol><li>管理画面 → 【メニュー管理】 → 【店舗メニュー】</li><li>画面下部の <strong>「今日のおすすめ」</strong> セクション（折りたたみ式）を展開</li><li>メニューを選択（最大 5 品目）</li><li><strong>【保存】</strong></li><li>日付指定で予約設定も可（翌日の「おすすめ」を事前登録）</li></ol><hr><h2 id="_3-12-品切れ切替-キッチンから即時反映" tabindex="-1">3-12. 品切れ切替（キッチンから即時反映） <a class="header-anchor" href="#_3-12-品切れ切替-キッチンから即時反映" aria-label="Permalink to &quot;3-12. 品切れ切替（キッチンから即時反映）&quot;">​</a></h2><h3 id="_3-12-1-管理画面から" tabindex="-1">3-12-1. 管理画面から <a class="header-anchor" href="#_3-12-1-管理画面から" aria-label="Permalink to &quot;3-12-1. 管理画面から&quot;">​</a></h3><ol><li>管理画面 → 【店舗メニュー】</li><li>該当メニューの <strong>「売切」トグル</strong> を ON</li><li>セルフメニューで「品切れ」バッジ表示</li><li>新規注文で該当メニューを選ぶとエラー</li></ol><h3 id="_3-12-2-kds-画面から" tabindex="-1">3-12-2. KDS 画面から <a class="header-anchor" href="#_3-12-2-kds-画面から" aria-label="Permalink to &quot;3-12-2. KDS 画面から&quot;">​</a></h3><p>キッチンスタッフが素早く切替できるように KDS 側にも UI あり。</p><ol><li>KDS 画面の <strong>【品切れ管理】</strong> ボタン</li><li>品切れにする品目をタップ</li><li>即反映</li></ol><hr><h2 id="_3-13-よくある質問" tabindex="-1">3-13. よくある質問 <a class="header-anchor" href="#_3-13-よくある質問" aria-label="Permalink to &quot;3-13. よくある質問&quot;">​</a></h2><p><strong>Q1. カテゴリを削除できない</strong></p><p>A1. そのカテゴリに紐付く品目がある場合は削除できません。先に該当品目のカテゴリを変更してから削除してください。</p><p><strong>Q2. 画像URL を公開サービスに置きたくない</strong></p><p>A2. 店舗のホームページや画像管理サービスに画像を置き、その画像URLを設定してください。画像アップロード機能は今後対応予定です。</p><p><strong>Q3. AI 翻訳が不正確</strong></p><p>A3. 固有名詞（「牛丼」→「Gyudon」等）は AI が一律翻訳しきれないので、手動修正してください。</p><p><strong>Q4. メニュー画像は必須？</strong></p><p>A4. 必須ではないですが、写真があるとお客様の注文率が大幅に上がります。最低でも主要メニューには画像を付けましょう。</p><p><strong>Q5. CSV インポートで日本語が文字化け</strong></p><p>A5. Excel の保存時に <strong>「CSV UTF-8」</strong> を選択してください（通常の CSV だと Shift-JIS で保存され文字化けの原因）。</p><hr><h2 id="_3-14-次のページへ" tabindex="-1">3-14. 次のページへ <a class="header-anchor" href="#_3-14-次のページへ" aria-label="Permalink to &quot;3-14. 次のページへ&quot;">​</a></h2><p>→ <a href="./part4-reports.html">Part 4: 売上とレポート</a></p>',145)])])}const b=l(i,[["render",e]]);export{u as __pageData,b as default};
